<script setup lang="ts">import{ref,computed}from'vue';import{useRouter}from'vue-router';import{Search,Plus}from'lucide-vue-next';import DefaultLayout from '@/layouts/default.vue';import CourseCard from '@/components/CourseCard.vue';import AppModal from '@/components/AppModal.vue';import{useCourseStore}from'@/stores/courses';const store=useCourseStore();const router=useRouter();const query=ref('');const status=ref('Все');const showCreate=ref(false);const title=ref('');const description=ref('');const filtered=computed(()=>store.courses.filter(c=>c.title.toLowerCase().includes(query.value.toLowerCase())&&(status.value==='Все'||c.status===status.value)));async function create(){if(!title.value.trim())return;const id=await store.createCourse(title.value,description.value||'Новая учебная программа');showCreate.value=false;router.push(`/app/courses/${id}`)}</script><template><DefaultLayout><div class="page-title"><div><h1>Курсы</h1><p>Создавайте, публикуйте и обновляйте учебные программы.</p></div><button class="primary" @click="showCreate=true"><Plus/>Создать курс</button></div><div class="toolbar"><label><Search/><input v-model="query" placeholder="Найти курс"/></label><button v-for="item in ['Все','Опубликован','Черновик']" :key="item" :class="['filter',status===item&&'active']" @click="status=item">{{item}}</button></div><section v-if="filtered.length" class="course-grid"><CourseCard v-for="course in filtered" :key="course.id" :course="course"/></section><section v-else class="empty-state"><Search/><h2>Курсы не найдены</h2><p>Измените поисковый запрос или создайте новый курс.</p></section><AppModal v-if="showCreate" title="Новый курс" @close="showCreate=false"><form class="form" @submit.prevent="create"><label>Название<input v-model="title" autofocus placeholder="Например, Основы испанского"/></label><label>Описание<textarea v-model="description" placeholder="Коротко расскажите о курсе"></textarea></label><div class="form-actions"><button type="button" class="ghost" @click="showCreate=false">Отмена</button><button class="primary">Создать курс</button></div></form></AppModal></DefaultLayout></template>